  ('diplomatic-90a202d9-moex-00338', 'diplomatic-90a202d9', 'diplomatic-90a202d9-moex-110-c655adf3', 'sub-diplomatic-90a202d9-05', NULL, 'single_choice', '我國國際空間屢屢遭受中共的打壓，請問下列那一個國際組織臺灣仍然是會員？', '["聯合國", "世界衛生組織", "世界貿易組織", "國際民用航空組織"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:06+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-馬來亞文組"}'::jsonb, NULL),
  ('diplomatic-90a202d9-moex-00339', 'diplomatic-90a202d9', 'diplomatic-90a202d9-moex-110-c655adf3', 'sub-diplomatic-90a202d9-05', NULL, 'single_choice', '我國為防範境外敵對勢力之滲透干預，確保國家安全及社會安定，維護國家主權及自由民主憲政秩序，特 於2020年1月制定反滲透法。下列敘述或情形何者正確？', '["所謂境外敵對勢力指與我國交戰或武力對峙之國家、政治實體或團體，但不包括主張採取非和平手段危 害我國主權之國家、政治實體或團體", "任何人不得受滲透來源之指示、委託或資助，進行遊說法第2條所定之遊說行為。違反規定者，處5年 以下有期徒刑，得併科新臺幣1千萬元以下罰金", "任何人不得受滲透來源之指示、委託或資助，為總統副總統選舉罷免法第 43 條或公職人員選舉罷免法 第45條各款行為。違反規定者，處5年以下有期徒刑，得併科新臺幣1千萬元以下罰金", "臺灣人民共產黨2021年7月1日於臺南紅船基地公開慶祝中國共產黨成立100周年，違反反滲透法， 得處5年以下有期徒刑，併科新臺幣1千萬元以下罰金"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:06+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-馬來亞文組"}'::jsonb, NULL),
  ('diplomatic-90a202d9-moex-00340', 'diplomatic-90a202d9', 'diplomatic-90a202d9-moex-110-c655adf3', 'sub-diplomatic-90a202d9-05', NULL, 'single_choice', '依據臺灣地區與大陸地區人民關係條例規定，臺灣地區人民具有特定身分者，進入大陸地區應經申請，並 經內政部會同國家安全局、法務部及大陸委員會組成之審查會審查許可。下列何者不包括在內？', '["政務人員", "立法委員", "直轄市長", "縣（市）長"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:06+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-馬來亞文組"}'::jsonb, NULL),
  ('diplomatic-90a202d9-moex-00341', 'diplomatic-90a202d9', 'diplomatic-90a202d9-moex-110-c655adf3', 'sub-diplomatic-90a202d9-05', NULL, 'single_choice', '我方駐港辦事處的中華民國國籍人員為何於2021年7月底以前全數撤離？', '["香港COVID-19疫情非常嚴重", "我國官員違反港版國安法", "我國官員拒絕簽署「一中承諾書」", "香港政府下令驅逐我國官員"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:06+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-馬來亞文組"}'::jsonb, NULL),
  ('diplomatic-90a202d9-moex-00342', 'diplomatic-90a202d9', 'diplomatic-90a202d9-moex-110-c655adf3', 'sub-diplomatic-90a202d9-05', NULL, 'single_choice', '針對中國繞過香港立法機構，強行通過「香港版國安法」立法的決議，大幅壓縮香港言論自由和司法獨立， 行政院提出什麼方案來幫助香港人民？', '["修改香港澳門關係條例", "制定難民法", "啟動「香港人道援助關懷行動專案」", "國際法庭控訴中共違反人權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:06+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-馬來亞文組"}'::jsonb, NULL),
  ('diplomatic-90a202d9-moex-00343', 'diplomatic-90a202d9', 'diplomatic-90a202d9-moex-110-c655adf3', 'sub-diplomatic-90a202d9-05', NULL, 'single_choice', '下列何者是李登輝總統主政期間推出的政策或措施？', '["提出一邊一國論", "成立海峽交流基金會", "開放大陸探親", "開放陸客來臺觀光"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:06+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-馬來亞文組"}'::jsonb, NULL),
  ('diplomatic-90a202d9-moex-00344', 'diplomatic-90a202d9', 'diplomatic-90a202d9-moex-110-c655adf3', 'sub-diplomatic-90a202d9-05', NULL, 'single_choice', '美、中兩國1972年所簽訂的「上海公報」中，下列那一項並非其重點內容？', '["美中關係正常化符合兩國利益", "美國認知一個中國原則，臺灣屬於中國的一部分", "美國將階段性削減駐臺軍隊及軍事設施", "美國將終止與臺灣簽訂的共同防禦條約"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:06+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-馬來亞文組"}'::jsonb, NULL),
  ('diplomatic-90a202d9-moex-00345', 'diplomatic-90a202d9', 'diplomatic-90a202d9-moex-110-c655adf3', 'sub-diplomatic-90a202d9-05', NULL, 'single_choice', '2021年7月1日，中共中央總書記習近平於《中共建黨百年》講話中主張要堅持一個中國原則和「九二共 識」，推進祖國和平統一進程。其實，習近平早在2019年1月2日《告臺灣同胞書》發表40周年紀念活 動發表談話時，就提出了「兩岸同屬一個中國，共同努力謀求國家統一」的九二共識。試問下列何者非習 近平的主張？', '["九二共識容許一中各表", "「和平統一、一國兩制」是實現國家統一的最佳方式", "制度不同，不是統一的障礙，更不是分裂的藉口。「一國兩制」的提出，本來就是為了照顧臺灣現實情 況，維護臺灣同胞利益福祉", "世界上只有一個中國，堅持一個中國原則是公認的國際關係準則，是國際社會普遍共識"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:06+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-馬來亞文組"}'::jsonb, NULL),
  ('diplomatic-90a202d9-moex-00346', 'diplomatic-90a202d9', 'diplomatic-90a202d9-moex-110-c655adf3', 'sub-diplomatic-90a202d9-05', NULL, 'single_choice', '「統一戰線」（或稱「統戰」）是中國共產黨的重要統治方式。請問關於「統一戰線」，下列何者錯誤？', '["2006年中共發布「關於鞏固和壯大新世紀新階段統一戰線的意見」，指出目前的統戰工作對象包括私營 企業與外資企業的管理技術人員", "根據憲法序言，中國人民政治協商會議是有廣泛代表性的統一戰線組織", "國務院內設有統戰部，由習近平直接領導", "統一戰線的說法，曾出現在列寧的著作中"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:06+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-馬來亞文組"}'::jsonb, NULL),
  ('diplomatic-90a202d9-moex-00347', 'diplomatic-90a202d9', 'diplomatic-90a202d9-moex-110-c655adf3', 'sub-diplomatic-90a202d9-05', NULL, 'single_choice', '中共政府經常召開眾多類型的黨政會議，請問「四中全會」所指為何？', '["全國人民代表大會中央委員會第4次全體會議", "中央人民政府第4次全體會議", "中國人民政治協商第4次全體會議", "中國共產黨中央委員會第4次全體會議"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:06+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-馬來亞文組"}'::jsonb, NULL)
